from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)
es = Elasticsearch(hosts=["http://localhost:9200"])

@app.route('/run_aggregation', methods=['POST'])
def run_aggregation():
    data = request.json
    user_script = data.get("script")
    index = data.get("index", "your-index-name")
    
    if not user_script:
        return jsonify({"error": "The 'script' field is required."}), 400

    # Aggregation query using a scripted_metric aggregation with the user input script.
    # Note: This example assumes the user provided script is for the "map_script" phase.
    query_body = {
        "size": 0,
        "aggs": {
            "dynamic_script_aggregation": {
                "scripted_metric": {
                    "init_script": "state.values = []",
                    "map_script": user_script,
                    "combine_script": "return state.values",
                    "reduce_script": """
                        double total = 0;
                        for (a in states) {
                          for (v in a) {
                            total += v;
                          }
                        }
                        return total;
                    """
                }
            }
        }
    }

    try:
        response = es.search(index=index, body=query_body)
    except Exception as e:
        return jsonify({"error": str(e)}), 500

    return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)